import{_ as r,c as a,o as t,ag as i}from"./chunks/framework.sL2pcHsl.js";const n="/assets/Map.Crvuru8T.png",u=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"start/instruction.md","filePath":"start/instruction.md"}'),o={name:"start/instruction.md"};function l(s,e,p,c,h,_){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>OpenLayers 是开源的前端地图引擎，主要用于二维地图渲染。功能齐全，API 丰富，支持多种地图投影和图层类型。</p><h2 id="地图组成" tabindex="-1">地图组成 <a class="header-anchor" href="#地图组成" aria-label="Permalink to &quot;地图组成&quot;">​</a></h2><p>Map 是 OpenLayers 的核心组件，其构成如下 <img src="'+n+'" alt="地图"></p><ul><li>一个地图有一个 View 对象，控制地图的中心点、缩放比例、旋转，view 有一个 projection 属性，决定了地图的坐标系，默认是 Web墨卡托(EPSG:3857)。</li><li>一个地图可以有多个图层，一个图层对应一个数据源。</li><li>控件是固定在屏幕上的 DOM 元素，位置和样式由 css 控制。</li><li>Interaction 与 DOM 元素无关，是一些改变地图状态的用户行为，比如ol/interaction/DoubleClickZoom.js允许用户双击缩放地图。</li><li>Overlay 显示在地图上的 DOM 元素，并且和地理坐标关联，不会固定在屏幕位置上，当拖动地图时，Overlay 也会跟随移动，永远和关联的地理坐标保持相对的屏幕位置。常用作展示和地理要素关联的业务信息。</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><p><a href="https://openlayers.org/" target="_blank" rel="noreferrer">OpenLayers 官方网站</a><br><a href="https://linwei.xyz/ol3-primer/ch01/index.html" target="_blank" rel="noreferrer">OpenLayers 教程（基础知识通俗易懂）</a><br><a href="https://viglino.github.io/ol-ext/" target="_blank" rel="noreferrer">OpenLayers 扩展库</a></p>',7)])])}const f=r(o,[["render",l]]);export{u as __pageData,f as default};
